import React from "react";
import { BrowserRouter, Route, Link } from "react-router-dom";
import "./App.css";
import Collapsible from "./components/Collapsible";
import Sub from "./components/SubCategories";

function App() {
  return (
    <BrowserRouter>
      <div>
        <Collapsible />
        <Route path="/subcategories/:category" component={Sub} />
      </div>
    </BrowserRouter>
  );
}

export default App;
